pub struct CassCollector;

#[async_trait]
impl Collector for CassCollector {
    fn name(&self) -> &'static str { "cass" }
    fn schema_version(&self) -> u32 { 1 }
    fn required_tool(&self) -> Option<&'static str> { Some("cass") }

    async fn collect(&self, ctx: &CollectContext) -> CollectResult {
        let collected_at = Utc::now();
        let mut rows = vec![];

        // Health status
        if let Ok(output) = ctx.executor.run_timeout("cass health --json", ctx.timeout).await {
            if let Ok(health) = serde_json::from_str::<CassHealthOutput>(&output) {
                rows.push(RowBatch {
                    table: "cass_index_status",
                    rows: vec![serde_json::json!({
                        "machine_id": ctx.machine_id.as_str(),
                        "collected_at": collected_at.to_rfc3339(),
                        "state": health.state,
                        "total_sessions": health.total_sessions,
                        "last_index_at": health.last_index_at,
                        "raw_json": output,
                    })],
                });
            }
        }

        // Stats
        if let Ok(output) = ctx.executor.run_timeout("cass stats --json", ctx.timeout).await {
            if let Ok(stats) = serde_json::from_str::<CassStatsOutput>(&output) {
                // Store overall metrics
                rows.push(RowBatch {
                    table: "cass_stats_snapshots",
                    rows: vec![
                        serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "metric_name": "total_conversations",
                            "metric_value": stats.total_conversations,
                            "dimensions_json": "{}",
                        }),
                        serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "metric_name": "total_messages",
                            "metric_value": stats.total_messages,
                            "dimensions_json": "{}",
                        }),
                    ],
                });

                // Store per-agent breakdown
                for (agent, count) in &stats.by_agent {
                    rows.push(RowBatch {
                        table: "cass_stats_snapshots",
                        rows: vec![serde_json::json!({
                            "machine_id": ctx.machine_id.as_str(),
                            "collected_at": collected_at.to_rfc3339(),
                            "metric_name": "sessions_by_agent",
                            "metric_value": count,
                            "dimensions_json": format!(r#"{{"agent":"{}"}}"#, agent),
                        })],
                    });
                }
            }
        }

        CollectResult { rows, ..Default::default() }
    }
}
```

